INSERT INTO public.exam_templates (id, title, total_questions, total_parts, description, sub_title, theme, parts) VALUES ('49bbc155-38cf-4d60-913e-be3c9bea8a67', 'TOEIC HAS PART 4', 200, 7, null, null, 'CAMBRIDGE_YLE', '[{"id": 1, "name": "Part 1", "skill": "LISTENING", "points": 6, "isGroup": false, "audioUrl": "", "category": "LISTENING", "endIndex": 5, "optionMode": "TEXT", "startIndex": 0, "optionCount": 4, "defaultValue": ["A", "B", "C", "D"], "instructions": "Directions: For each question in this part, you will hear four statements about a picture in your test book. When you hear the statements, you must select the one statement that best describes what you see in the picture. Then find the number of the question on your answer sheet and mark your answer. The statements will not be printed in your test book and will be spoken only one time.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 6, "questionConfig": ["imageUrl", "options"]}, {"id": 2, "name": "Part 2", "skill": "LISTENING", "points": 25, "isGroup": false, "audioUrl": "", "category": "LISTENING", "endIndex": 30, "optionMode": "TEXT", "startIndex": 6, "optionCount": 4, "defaultValue": ["A", "B", "C", "D"], "instructions": "You will hear a question or statement and three responses spoken in English. They will not be printed in your test book and will be spoken only one time. Select the best response to the question or statement and mark the letter (A), (B), or (C) on your answer sheet.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 25, "questionConfig": ["options"]}, {"id": 3, "name": "Part 3", "skill": "LISTENING", "points": 39, "isGroup": false, "audioUrl": "", "category": "LISTENING", "endIndex": 69, "optionMode": "TEXT", "startIndex": 31, "optionCount": 4, "instructions": "You will hear some conversations between two or more people. You will be asked to answer three questions about what the speakers say in each conversation. Select the best response to each question and mark the letter (A), (B), (C), or (D) on your answer sheet. The conversations will not be printed in your test book and will be spoken only one time.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 39, "questionConfig": ["question", "options", "imageUrl"]}, {"id": 4, "name": "Part 4", "skill": "LISTENING", "points": 30, "isGroup": false, "audioUrl": "", "category": "LISTENING", "endIndex": 99, "optionMode": "TEXT", "startIndex": 70, "optionCount": 4, "instructions": "You will hear some talks given by a single speaker. You will be asked to answer three questions about what the speaker says in each talk. Select the best response to each question and mark the letter (A), (B), (C), or (D) on your answer sheet. The talks will not be printed in your test book and will be spoken only one time.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 30, "questionConfig": ["question", "options"]}, {"id": 4, "name": "Part 5", "skill": "READING", "points": 30, "isGroup": false, "category": "READING", "endIndex": 129, "optionMode": "TEXT", "startIndex": 100, "optionCount": 4, "instructions": "A word or phrase is missing in each of the sentences below. Four answer choices are given below each sentence. Select the best answer to complete the sentence. Then mark the letter (A), (B), (C), or (D) on your answer sheet.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 30, "questionConfig": ["question", "options"]}, {"id": 5, "name": "Part 6", "group": {"type": "DOCUMENT", "items": [{"number": 1, "questionCount": 4}, {"number": 2, "questionCount": 4}, {"number": 3, "questionCount": 4}, {"number": 4, "questionCount": 4}]}, "skill": "READING", "points": 16, "isGroup": true, "category": "READING", "endIndex": 145, "optionMode": "TEXT", "startIndex": 130, "optionCount": 4, "instructions": "Read the texts that follow. A word, phrase, or sentence is missing in parts of each text. Four answer choices for each question are given below the text. Select the best answer to complete the text. Then mark the letter (A), (B), (C), or (D) on your answer sheet.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 16, "questionConfig": ["options"]}, {"id": 6, "name": "Part 7", "group": {"type": "ARTICLES", "items": [{"number": 1, "questionCount": 2}, {"number": 2, "questionCount": 2}, {"number": 3, "questionCount": 2}, {"number": 4, "questionCount": 2}, {"number": 5, "questionCount": 3}, {"number": 6, "questionCount": 3}, {"number": 7, "questionCount": 3}, {"number": 8, "questionCount": 4}, {"number": 9, "questionCount": 4}, {"number": 10, "questionCount": 4}, {"number": 11, "questionCount": 5}, {"number": 12, "questionCount": 5}, {"number": 13, "questionCount": 5}, {"number": 14, "questionCount": 5}, {"number": 15, "questionCount": 5}]}, "skill": "READING", "points": 16, "isGroup": true, "category": "READING", "endIndex": 199, "optionMode": "TEXT", "startIndex": 146, "optionCount": 4, "instructions": "In this part you will read a selection of texts, such as magazine and newspaper articles, e-mails, and instant messages. Each text or set of texts is followed by several questions. Select the best answer for each question and mark the letter (A), (B), (C), or (D) on your answer sheet.", "questionType": "CHOOSE_THE_CORRECT_ANSWER", "questionCount": 54, "questionConfig": ["question", "options"]}]');
