INSERT INTO public.exam_templates (id, title, total_questions, total_parts, description, sub_title, theme, parts) VALUES ('f451e33c-6e9d-4994-bcc2-6be5319adbe1', 'IELTS QE Speaking', 9, 3, null, null, 'SUMMER_SKY', '[{"id": 1, "name": "Part 1", "skill": "SPEAKING", "points": 4, "endIndex": 3, "startIndex": 0, "description": "Answer questions about yourself and familiar topics. Respond naturally.", "optionCount": null, "instructions": "In this part, the examiner will ask you some questions about yourself, your home, work or studies and other familiar topics.", "questionType": "SPONTANEOUS_QA", "questionCount": 4}, {"id": 2, "name": "Part 2", "skill": "SPEAKING", "points": 1, "endIndex": 4, "startIndex": 4, "description": "Read the cue card. You have 1 minute to prepare. Then speak for 1 to 2 minutes.", "optionCount": null, "instructions": "You will have to talk about the topic for 1 to 2 minutes. You have 1 minute to think about what you’re going to say.", "questionType": "SPEAKING_CUE_CARD", "questionCount": 1}, {"id": 3, "name": "Part 3", "skill": "SPEAKING", "points": 4, "endIndex": 8, "startIndex": 5, "description": "Discuss abstract issues related to the topic in Part 2. Give detailed answers.", "optionCount": null, "instructions": "We''ve been talking about the topic in Part 2, and I''d now like to ask you some more general questions related to this.", "questionType": "SPONTANEOUS_QA", "questionCount": 4}]');
INSERT INTO public.exam_templates (id, title, total_questions, total_parts, description, sub_title, theme, parts) VALUES ('124939bb-3866-4812-a174-d7595eb3d73b', 'KEY FOR SCHOOLS SPEAKING', 25, 2, null, null, 'SPACESHIP', '[{"id": 1, "name": "Part 1", "skill": "SPEAKING", "points": 10, "isGroup": false, "category": "SPEAKING", "endIndex": 9, "sections": [{"name": "Phase 1", "endIndex": 4, "sectionId": 1, "startIndex": 0, "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 5}, {"name": "Phase 2", "endIndex": 9, "sectionId": 2, "startIndex": 5, "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 5}], "startIndex": 0, "instructions": "The interlocutor asks personal questions. Listen to the partner answer first, then answer when it is your turn.", "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 10}, {"id": 2, "name": "Part 2", "skill": "SPEAKING", "points": 25, "isGroup": false, "category": "SPEAKING", "endIndex": 24, "sections": [{"name": "Phase 1A — Talk Together", "endIndex": 15, "sectionId": 1, "startIndex": 10, "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 6}, {"name": "Phase 1B — Follow-up Questions", "endIndex": 19, "sectionId": 2, "startIndex": 16, "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 4}, {"name": "Phase 2 — Comparative Questions", "endIndex": 24, "sectionId": 3, "startIndex": 20, "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 5}], "startIndex": 10, "instructions": "Look at the pictures and discuss. Answer the examiner''s questions about the topic.", "questionType": "GN_SPEAKING_INTERVIEW", "questionCount": 15}]');
